#include <bits/stdc++.h>using namespace std;#define int long long int#define all(x) x.begin(), x.end() void solve() {    string s; cin >> s;    int bal = 0;    int n = s.size();    for (int i = 0; i + 1 < n; i++) if (s[i] == s[i + 1]) bal++;    if (bal <= 2) cout << "YES\n";    else cout << "NO\n";}int32_t main() {    ios_base::sync_with_stdio(0); cin.tie(0);    int t = 1; cin >> t;    while (t--) solve();    return 0;}